const raw = $input.all()[0].json;
const content = raw.choices[0].message.content;
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = { clinical: true }; }
const isClinical = parsed.clinical !== false;

const body = $('Webhook').first().json.body;

return [{ json: {
  guardrail_clinical: isClinical,
  route: isClinical ? 'pass' : 'block',
  complaint_text: body.complaint_text,
  vitals: body.vitals || {}
}}];

const raw = $input.all()[0].json.choices[0].message.content;
let brief;
try { brief = JSON.parse(raw); } catch(e) { brief = { esi_level: 2, acuity: 'high', primary_flag: 'parse_error' }; }

const guardrailUsage = $('Guardrail Check').item.json.usage || {};
const classifyUsage  = $('Quick Classify').item.json.usage || {};
const briefUsage     = $input.all()[0].json.usage || {};

const prompt_tokens     = (guardrailUsage.prompt_tokens || 0) + (classifyUsage.prompt_tokens || 0) + (briefUsage.prompt_tokens || 0);
const completion_tokens = (guardrailUsage.completion_tokens || 0) + (classifyUsage.completion_tokens || 0) + (briefUsage.completion_tokens || 0);

return [{ json: { ...brief, usage: { prompt_tokens, completion_tokens, total_tokens: prompt_tokens + completion_tokens } } }];

