const input = $input.all()[0].json;

const guardrailUsage = $('Guardrail Check').item.json.usage || {};
const classifyUsage  = $('Quick Classify').item.json.usage || {};

const prompt_tokens     = (guardrailUsage.prompt_tokens || 0) + (classifyUsage.prompt_tokens || 0);
const completion_tokens = (guardrailUsage.completion_tokens || 0) + (classifyUsage.completion_tokens || 0);

const recommended_actions = [
  'Complete triage vitals assessment',
  'Register and complete patient intake forms',
  input.esi_level <= 4 ? 'Assign to fast track — provider evaluation within 60 minutes' : 'Waiting room — provider evaluation when available'
];

return [{ json: {
  esi_level: input.esi_level,
  acuity: input.acuity,
  primary_flag: input.primary_flag,
  complaint_summary: input.complaint_summary,
  recommended_actions,
  clinical_notes: 'Non-urgent presentation with stable vitals. No immediate clinical intervention required. Notify triage nurse if symptoms worsen or any new symptoms develop.',
  disposition: input.esi_level <= 4 ? 'fast_track' : 'waiting_room',
  confidence: 'high',
  usage: { prompt_tokens, completion_tokens, total_tokens: prompt_tokens + completion_tokens }
} }];
